        public string Password { get; set; } = string.Empty;

        [RegularExpression(@@"^([0-9]{6})|([A-Z0-9]{5}[-]{1}[A-Z0-9]{5})$", 
            ErrorMessage = "Must be 6-digit code (######) or " +
                          "recovery code (#####-#####)")]
        public string TwoFactorCodeOrRecoveryCode { get; set; } = string.Empty;
    }
