        $"https://profile-api/users/{userId}");
    var metricsTask = _httpClient.GetFromJsonAsync<UserMetrics>(
        $"https://metrics-api/users/{userId}/summary");
    var activityTask = _httpClient.GetFromJsonAsync<Activity[]>(
