// ❌ Wrong — giving Money its own table (and therefore an Id) makes it look like an Entity
// Table: Moneys  → | Id | Amount | Currency |      ← false Entity signal
// Table: Licenses → | Id | LicenseKey | MoneyId |  ← now it has a foreign key!

// ✅ Correct — EF Core OwnsOne embeds Money and DateRange columns into the Licenses table
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<License>(entity =>
    {
        // Money columns: Price_Amount, Price_Currency — stored IN the Licenses table
        entity.OwnsOne(l => l.Price, money =>
        {
            money.Property(m => m.Amount).HasColumnName("Price_Amount").HasPrecision(18, 2);
            money.Property(m => m.Currency).HasColumnName("Price_Currency").HasMaxLength(3);
        });

        // DateRange columns: ValidityPeriod_Start, ValidityPeriod_End — stored IN the Licenses table
        entity.OwnsOne(l => l.ValidityPeriod, range =>
        {
            range.Property(r => r.Start).HasColumnName("ValidityPeriod_Start");
            range.Property(r => r.End).HasColumnName("ValidityPeriod_End");
        });
    });
}

