var clientCommand = new CreateClientCommand();

using (var memoryContentStream = new MemoryStream())
{
    await JsonSerializer.SerializeAsync(memoryContentStream, clientCommand);

    memoryContentStream.Seek(0, SeekOrigin.Begin);

    using var request = new HttpRequestMessage(HttpMethod.Post, "/api/clients");
    request.Headers.AcceptEncoding.Add(new StringWithQualityHeaderValue("gzip"));

    using (var compressedMemoryContentStream = new MemoryStream())
    {
        using (var gzipStream = new GZipStream(compressedMemoryContentStream, CompressionMode.Compress, leaveOpen: true))
        {
            memoryContentStream.CopyTo(gzipStream);
            gzipStream.Flush();

            compressedMemoryContentStream.Position = 0;

            using var streamContent = new StreamContent(compressedMemoryContentStream);
            streamContent.Headers.ContentType = new MediaTypeHeaderValue(MediaTypeNames.Application.Json);
            streamContent.Headers.ContentEncoding.Add("gzip");
            request.Content = streamContent;

            var response = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead);

            response.EnsureSuccessStatusCode();
        }
    }
}

