using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public sealed class LogScopeMiddleware(
    ILogger<LogScopeMiddleware> logger,
    ITenantService tenantService) : IMiddleware
{
    public async Task InvokeAsync(HttpContext context, RequestDelegate next)
    {
        if (context.User.Identity is { IsAuthenticated: true })
        {
            using (logger.BeginScope(
                "Request {RequestId}, Client {ClientId}, Branch {BranchId}, User {UserId}",
                context.TraceIdentifier,
                tenantService.GetClientId(),
                tenantService.GetBranchId(),
                tenantService.GetCurrentUser()))
            {
                await next(context);
            }
        }
        else
        {
            await next(context);
        }
    }
}

public static class LogScopeMiddlewareExtensions
{
    public static IApplicationBuilder UseLogScope(
        this IApplicationBuilder builder)
    {
        return builder.UseMiddleware<LogScopeMiddleware>();
    }
}
