// Controllers/OrdersController.cs
[ApiController]
[Route("api/[controller]")]
public class OrdersController : ControllerBase
{
    private readonly IOrderService _orderService;
    private readonly ILogger<OrdersController> _logger;

    public OrdersController(
        IOrderService orderService,
        ILogger<OrdersController> logger)
    {
        _orderService = orderService;
        _logger = logger;
    }

    [HttpPost]
    public async Task<IActionResult> CreateOrder(
        [FromBody] CreateOrderRequest request)
    {
        // Use scopes to add context to all logs within this method
        using (_logger.BeginScope(new Dictionary<string, object>
        {
            ["CustomerId"] = request.CustomerId,
            ["ItemCount"] = request.Items.Count
        }))
        {
            _logger.LogInformation("Received order creation request");

            try
            {
                var order = await _orderService.CreateAsync(request);

                _logger.LogInformation(
                    "Order {OrderId} created successfully with total {Total:C}", 
                    order.Id, 
                    order.Total);

                return CreatedAtAction(nameof(GetOrder), 
                    new { id = order.Id }, order);
            }
            catch (ValidationException ex)
            {
                _logger.LogWarning(ex, 
                    "Order validation failed: {Errors}", 
                    string.Join(", ", ex.Errors));
                return BadRequest(ex.Errors);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error creating order");
                return StatusCode(500, "An error occurred");
            }
        }
    }

    [HttpGet("{id}")]
    public async Task<IActionResult> GetOrder(string id)
    {
        _logger.LogDebug("Fetching order {OrderId}", id);

        var order = await _orderService.GetByIdAsync(id);

        if (order == null)
        {
            _logger.LogWarning("Order {OrderId} not found", id);
            return NotFound();
        }

        return Ok(order);
    }
}

