static string ConvertFluentAssertionsToXUnit(string input)
{
    // 1. Replace .Should().Be with Assert.Equal
    input = Regex.Replace(input, @@"((?:[\w\[\]\.!]+(?:\.\w+|\(.*\))*))\.Should\(\)\.Be\((.*)\);", @@"Assert.Equal($2, $1);");

    // 2. Replace .Should().Equal() with Assert.Equal()
    input = Regex.Replace(input, @@"((?:[\w\[\]\.!]+(?:\.\w+|\(.*\))*))\.Should\(\)\.Equal\((.*)\);", @@"Assert.Equal($2, $1);");

    // 3. Replace .Should().NotBe with Assert.NotEqual
