public class SsrfProtectionService
{
    private static readonly HashSet<string> BlockedIpRanges = new()
    {
        "127.0.0.0/8",      // Loopback
        "10.0.0.0/8",       // Private network
        "172.16.0.0/12",    // Private network
        "192.168.0.0/16",   // Private network
        "169.254.0.0/16",   // Link-local (cloud metadata)
        "::1/128",          // IPv6 loopback
        "fc00::/7"          // IPv6 private
    };

    public bool IsUrlSafe(Uri uri)
    {
        // Block non-HTTP(S) schemes
        if (uri.Scheme != "http" && uri.Scheme != "https")
        {
            return false;
        }

        // Resolve hostname to IP address
        try
        {
            var hostEntry = Dns.GetHostEntry(uri.Host);

            // Check each resolved IP address
            foreach (var ipAddress in hostEntry.AddressList)
            {
                if (IsPrivateOrLocalIp(ipAddress))
                {
                    return false;
                }
            }
        }
        catch (SocketException)
        {
            // DNS resolution failed - reject
            return false;
        }

        return true;
    }

    private bool IsPrivateOrLocalIp(IPAddress ipAddress)
    {
        var bytes = ipAddress.GetAddressBytes();

        // IPv4 checks
        if (ipAddress.AddressFamily == AddressFamily.InterNetwork)
        {
            // 127.x.x.x (loopback)
            if (bytes[0] == 127)
                return true;

            // 10.x.x.x (private)
            if (bytes[0] == 10)
                return true;

            // 172.16.x.x - 172.31.x.x (private)
            if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                return true;

            // 192.168.x.x (private)
            if (bytes[0] == 192 && bytes[1] == 168)
                return true;

            // 169.254.x.x (link-local, cloud metadata)
            if (bytes[0] == 169 && bytes[1] == 254)
                return true;
        }

        // IPv6 checks
        if (ipAddress.AddressFamily == AddressFamily.InterNetworkV6)
        {
            // ::1 (loopback)
            if (IPAddress.IsLoopback(ipAddress))
                return true;

            // fc00::/7 (private)
            if ((bytes[0] & 0xfe) == 0xfc)
                return true;
        }

        return false;
    }
}
