        var result = new char[length];
        for (int i = 0; i < length; i++)
        {
            int index = RandomNumberGenerator.GetInt32(0, AlphaNumericChars.Length);
            result[i] = AlphaNumericChars[index];
        }

        return new string(result);
    }

