            .Replace('+', '-')
            .Replace('/', '_'); // URL-safe characters
    }

    public string GenerateHexToken(int byteLength)
    {
        byte[] randomBytes = GenerateRandomBytes(byteLength);
        return Convert.ToHexString(randomBytes);
    }

