		{
			builder.ConfigureTestServices(services =>
			{
				var descriptor = services.SingleOrDefault(d => d.ServiceType == typeof(AuthClaimsProvider));

				if (descriptor != null)
				{
					services.Remove(descriptor);
					services.AddScoped(_ => claims);
				}
			});
		})
		.CreateClient();

		return client;
	}
