public sealed class LogScopeMiddleware : IMiddleware
{
    private readonly ILogger<LogScopeMiddleware> _logger;
    private readonly ITenantService _tenantService;

    public LogScopeMiddleware(ILogger<LogScopeMiddleware> logger, ITenantService tenantService)
    {
        _logger = logger;
        _tenantService = tenantService;
    }

    public async Task InvokeAsync(HttpContext context, RequestDelegate next)
    {
        if (context.User.Identity.IsAuthenticated)
        {
            using (_logger.BeginScope("Request {RequestId}, Tenant {TenantId}, User {UserId}",
            context.TraceIdentifier, _tenantService.GetTenantId(), _tenantService.GetCurrentUser()))
            {
                await next(context);
            }
        }
        else
        {
            await next(context);
        }
    }
}

public static class LogScopeMiddlewareExtensions
{
    public static IApplicationBuilder UseLogScope(this IApplicationBuilder builder)
    {
        return builder.UseMiddleware<LogScopeMiddleware>();
