namespace ILoveDotNet.HostedServices;

public class ILoveDotNetAthenaQueryBackgroundService(
    ILogger<ILoveDotNetAthenaQueryBackgroundService> logger,
    TimeProvider timeProvider,
    IServiceProvider serviceProvider) : BackgroundService
{
  private const int QueryIntervalInMinutes = 30;
  private string _currentInstanceId = string.Empty;

  protected override async Task ExecuteAsync(CancellationToken stoppingToken)
  {
    await RegisterInstance($"ilovedotnet-bg-metrics-process-{Guid.NewGuid().ToString()}");

    timeProvider.CreateTimer(ReadDataFromAthena, null, TimeSpan.Zero, TimeSpan.FromMinutes(QueryIntervalInMinutes));
  }

  private async Task RegisterInstance(string processTrackingId)
  {
    try
    {
      using var scope = serviceProvider.CreateScope();
      var configRepo = scope.ServiceProvider.GetRequiredService<IRepository<Settings>>();
      var instanceService = scope.ServiceProvider.GetRequiredService<IAwsInstanceService>();

      if (string.IsNullOrEmpty(_currentInstanceId))
      {
        _currentInstanceId = instanceService.GetInstanceId();
      }

      var existingConfig = await configRepo.GetByIdAsync("ilovedotnet-bg-service");
      if (existingConfig != null)
      {
        existingConfig.UpdateValue(_currentInstanceId);
        configRepo.Update(existingConfig);
      }
      else
      {
        var config = new Settings("ilovedotnet-bg-service", _currentInstanceId);
        await configRepo.AddAsync(config);
      }

      await configRepo.SaveChangesAsync();
    }
    catch
    {
      // log error
    }
  }

  private async void ReadDataFromAthena(object? sender)
  {
    try
    {
      using var scope = serviceProvider.CreateScope();
      var metricsService = scope.ServiceProvider.GetRequiredService<IMetricsService>();
      var settingsRepo = scope.ServiceProvider.GetRequiredService<IRepository<Settings>>();
      var instanceService = scope.ServiceProvider.GetRequiredService<IAwsInstanceService>();

      var settings = await settingsRepo.GetByIdAsync("ilovedotnet-bg-service");
      _currentInstanceId = instanceService.GetInstanceId();

      var canExecute = await CanExecute(settings, _currentInstanceId);

      if (!canExecute)
      {
        // log and return
        return;
      }

      await metricsService.ProcessMetrics();

      // Resetting / Update instance id after saving metrics

      await RegisterInstance(processTrackingId);
    }
    catch (Exception e)
    {
      // log exception
    }
  }

  private async Task<bool> CanExecute(Settings? setting, string currentInstanceId)
  {
    if (setting == null)
    {
      return await Task.FromResult(false);
    }

    var thresholdTime = setting.LastUpdatedAt.AddMinutes(QueryIntervalInMinutes * 2);

    var bgProcessorInstanceId = GetProcessorInstanceId(setting);

    var currentUtcTime = timeProvider.GetUtcNow().DateTime;
    var isThresholdCrossed = thresholdTime < currentUtcTime;

    return currentInstanceId.Equals(bgProcessorInstanceId, StringComparison.InvariantCultureIgnoreCase)
      || isThresholdCrossed;
  }
}

