    private const int MaxMessagesInChannel = 10;
    private readonly Channel<bool> channel;

    public DataMigrationChannel()
    {
        var options = new BoundedChannelOptions(MaxMessagesInChannel)
        {
            SingleWriter = true,
            SingleReader = true
        };

        channel = Channel.CreateBounded<bool>(options);
    }

    public async Task<bool> MigrateData(bool start, CancellationToken cancellationToken)
    {
        while (await channel.Writer.WaitToWriteAsync(cancellationToken) && !cancellationToken.IsCancellationRequested)
        {
            if (channel.Writer.TryWrite(start))
            {
                return true;
            }
        }

        return false;
    }

    public IAsyncEnumerable<bool> ReadAllAsync(CancellationToken cancellationToken) => channel.Reader.ReadAllAsync(cancellationToken);
}
